type data_partition = {
  partition_name : LString.t;
  is_visible : bool;
}

type file_section = {
  section_name : LString.t;
  is_visible : bool;
}

type report = {
  partitions : data_partition list;
  sections : file_section list;
}

let get_visible_sections (r : report) : file_section list =
  List.filter (fun (s : file_section) -> s.is_visible) r.sections

let get_visible_partitions (r : report) : data_partition list =
  List.filter (fun (p : data_partition) -> p.is_visible) r.partitions
